    for i, part in enumerate(parts):
        if '/' in part and (len(part.split('/')) == 2):
            project_idx = i
        if part.startswith('forks') and i + 3 < len(parts):
            try:
                forks_count = int(parts[i+3].rstrip('.,'))
                forks_idx = i
                break
            except:
                try:
                    forks_count = int(parts[i+2].rstrip('.,'))
                    forks_idx = i
                    break
                except:
                    continue

    if forks_idx > 0:
        if project_idx > 0:
            project_name = parts[project_idx].rstrip('.,')
            fork_dict[project_name] = forks_count

print('Projects with fork data:', len(fork_dict))

# Step 5: Find intersection
top_projects = []
for info in project_infos:
    text = info['Project_Information']
    parts = text.split()

    for i, part in enumerate(parts):
        if '/' in part and len(part.split('/')) == 2:
            project_name = part.rstrip('.,')
            if project_name in unique_projects:
                for j in range(i, min(i+10, len(parts))):
                    if parts[j].startswith('forks'):
                        try:
                            count = int(parts[j+3].rstrip('.,'))
                            top_projects.append({
                                'project': project_name,
                                'forks': count,
                                'package': unique_projects[project_name]
                            })
                            break
                        except:
                            try:
                                count = int(parts[j+2].rstrip('.,'))
                                top_projects.append({
                                    'project': project_name,
                                    'forks': count,
                                    'package': unique_projects[project_name]
                                })
                                break
                            except:
                                continue

# Step 6: Sort and return top 5
sorted_projects = sorted(top_projects, key=lambda x: x['forks'], reverse=True)
print('Total matched projects:', len(sorted_projects))
print('\nTop 10 by forks:')
for i, p in enumerate(sorted_projects[:10], 1):
    print(f"{i}. {p['project']} - {p['forks']} forks") 

# Print final result
result = sorted_projects[:5]
print('__RESULT__:')
print(json.dumps(result))
